// 웹훅 데이터 파싱 및 유효성 검사
const body = $input.first().json.body;

if (!body.authKey || !body.customerKey) {
  throw new Error('필수 파라미터 누락: authKey, customerKey');
}

// 플랜별 결제 금액 및 이름 설정
const PLANS = {
  'MONTHLY': { amount: 29800, name: '임원Signal 월간 구독', period: '1개월' },
  'ANNUAL':  { amount: 237600, name: '임원Signal 연간 구독', period: '12개월' }
};

const plan = body.plan || 'MONTHLY';
const planInfo = PLANS[plan] || PLANS['MONTHLY'];

// 구독 만료일 계산
const now = new Date();
const expiry = new Date(now);
if (plan === 'ANNUAL') {
  expiry.setFullYear(expiry.getFullYear() + 1);
} else {
  expiry.setMonth(expiry.getMonth() + 1);
}

const orderId = `ES-${Date.now()}-${Math.random().toString(36).substr(2,6).toUpperCase()}`;

return [{
  json: {
    authKey:        body.authKey,
    customerKey:    body.customerKey,
    receiveEmail:   body.receiveEmail || '',
    firebaseUid:    body.firebaseUid || '',
    plan:           plan,
    amount:         planInfo.amount,
    planName:       planInfo.name,
    planPeriod:     planInfo.period,
    orderId:        orderId,
    subscriptionEndDate: expiry.toISOString().split('T')[0],
    createdAt:      now.toISOString()
  }
}];

const prev = $('Parse_And_Validate').first().json;
const tossResp = $input.first().json;

// 빌링키 발급 실패 처리
if (tossResp.code) {
  throw new Error(`[Toss 오류] ${tossResp.code}: ${tossResp.message}`);
}

const billingKey = tossResp.billingKey;
if (!billingKey) {
  throw new Error('빌링키 발급 실패: billingKey가 없습니다.');
}

return [{
  json: {
    ...prev,
    billingKey: billingKey,
    cardCompany: tossResp.card?.company || '',
    cardNumber: tossResp.card?.number || ''
  }
}];

const prev = $('Extract_BillingKey').first().json;
const chargeResp = $input.first().json;

// 결제 실패 처리
if (chargeResp.code || chargeResp.status === 'ABORTED' || chargeResp.status === 'EXPIRED') {
  throw new Error(`[결제 실패] ${chargeResp.code}: ${chargeResp.message}`);
}

const paidAmount = chargeResp.totalAmount || prev.amount;
const paymentKey = chargeResp.paymentKey || '';

return [{
  json: {
    ...prev,
    paymentKey:  paymentKey,
    paidAmount:  paidAmount,
    payStatus:   chargeResp.status || 'DONE'
  }
}];

const d = $input.first().json;

const planKr   = d.plan === 'ANNUAL' ? '연간 구독 (12개월)' : '월간 구독';
const amountFmt = Number(d.paidAmount).toLocaleString('ko-KR');

const html = `
<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Apple SD Gothic Neo', Arial, sans-serif; background: #0A0C10; color: #ffffff; margin: 0; padding: 0; }
    .wrap { max-width: 600px; margin: 0 auto; padding: 40px 20px; }
    .logo { font-size: 1.4rem; font-weight: 800; margin-bottom: 32px; }
    .logo span { color: #D4AF37; }
    .card { background: #161B22; border: 1px solid rgba(255,255,255,0.08); border-radius: 16px; padding: 32px; margin-bottom: 24px; }
    h2 { font-size: 1.4rem; font-weight: 700; margin-bottom: 8px; }
    .sub { color: #8B949E; font-size: 0.9rem; margin-bottom: 24px; }
    .badge { display: inline-block; background: linear-gradient(135deg,#D4AF37,#B38F2D); color: #000; font-weight: 700; font-size: 0.75rem; padding: 4px 14px; border-radius: 20px; letter-spacing: 1px; margin-bottom: 20px; }
    table { width: 100%; border-collapse: collapse; }
    td { padding: 10px 0; border-bottom: 1px solid rgba(255,255,255,0.05); font-size: 0.9rem; }
    td:first-child { color: #8B949E; }
    td:last-child { text-align: right; font-weight: 500; }
    tr:last-child td { border-bottom: none; }
    .highlight { color: #D4AF37; }
    .cta { display: block; text-align: center; margin-top: 28px; }
    .cta a { background: linear-gradient(135deg,#D4AF37,#B38F2D); color: #000; text-decoration: none; padding: 14px 36px; border-radius: 8px; font-weight: 700; font-size: 0.95rem; }
    .footer { color: #444; font-size: 0.78rem; text-align: center; margin-top: 32px; line-height: 1.6; }
  </style>
</head>
<body>
<div class="wrap">
  <div class="logo">Executive<span>Signal</span></div>
  <div class="card">
    <h2>🎉 구독이 완료되었습니다!</h2>
    <p class="sub">임원 매수 신호를 가장 먼저 받아보실 준비가 됐습니다.</p>
    <div class="badge">${d.plan}</div>
    <table>
      <tr><td>구독 플랜</td><td>${planKr}</td></tr>
      <tr><td>리포트 수신 이메일</td><td>${d.receiveEmail}</td></tr>
      <tr><td>결제 금액</td><td class="highlight">₩${amountFmt}</td></tr>
      <tr><td>구독 만료일</td><td>${d.subscriptionEndDate}</td></tr>
      <tr><td>주문 번호</td><td style="font-size:0.8rem;">${d.orderId}</td></tr>
    </table>
    <div class="cta">
      <a href="https://executivesignal.com">서비스 바로가기 →</a>
    </div>
  </div>
  <p class="footer">
    내일 아침 8:00부터 매일 리포트가 발송됩니다.<br>
    구독 해지 및 문의: support@executivesignal.com<br>
    본 서비스는 DART 공시 데이터를 기반으로 하며, 모든 투자 판단의 책임은 본인에게 있습니다.
  </p>
</div>
</body>
</html>`;

return [{ json: { ...d, welcome_email_html: html } }];
